import rclpy
from rclpy.node import Node
from sensor_msgs.msg import Image
from cv_bridge import CvBridge
import rosbag
import os

class ROSBag_Publisher(Node):

    def __init__(self, bag_path):
        super().__init__("rosbag_publisher")
        self.publisher_ = self.create_publisher(Image, "/video_frames", 10)
        self.bridge = CvBridge()

        # Load the rosbag
        self.bag = rosbag.Bag(bag_path, 'r')

        # Extract video frames from rosbag (assuming topic contains sensor_msgs/Image messages)
        self.frames = self.bag.read_messages(topics=['/video_frames'])
        self.timer_period = 0.1  # 10 FPS, adjust as needed
        self.timer = self.create_timer(self.timer_period, self.publish_frame)

    def publish_frame(self):
        try:
            topic, msg, t = next(self.frames)
            self.publisher_.publish(msg)
        except StopIteration:
            print("End of ROS bag.")
            self.destroy_node()

def main(args=None):
    rclpy.init(args=args)
    print(" ROS bag publisher started")
    bag_path = os.path.join(os.path.dirname(__file__), 'your_rosbag.bag')  # Provide path to the ROS bag
    node = ROSBag_Publisher(bag_path)
    rclpy.spin(node)
    rclpy.shutdown()

if __name__ == '__main__':
    main()
